async function parseBinaryJson(itemIndex, binaryKey) {
  const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binaryKey);
  let text = buffer.toString("utf8");

  // Clean up the UTF-8 BOM
  text = text.replace(/^\uFEFF/, "");

  // Clean up any garbled or invisible characters that may have been mixed into the JSON.
  text = text.replace(/^[^\{\[]+/, "");

  return JSON.parse(text);
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function normalizeName(name) {
  return String(name || "").toLowerCase().trim();
}

function pickFirstNonEmpty(...values) {
  for (const value of values) {
    if (value == null) continue;
    if (typeof value === "string" && value.trim() === "") continue;
    return value;
  }
  return null;
}

function normalizeText(value) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function makeKey(item) {
  return [
    normalizeText(item?.title),
    normalizeText(item?.contract),
    normalizeText(item?.severity),
  ].join("||");
}

function uniqBy(list, getKey) {
  const map = new Map();

  for (const item of list) {
    const key = getKey(item);
    if (!key) continue;

    if (!map.has(key)) {
      map.set(key, item);
      continue;
    }

    const existing = map.get(key);
    map.set(key, {
      ...existing,
      ...item,
      my_finding: {
        ...existing.my_finding,
        ...item.my_finding,
        function: pickFirstNonEmpty(item?.my_finding?.function, existing?.my_finding?.function),
        confidence: pickFirstNonEmpty(item?.my_finding?.confidence, existing?.my_finding?.confidence),
        description: pickFirstNonEmpty(item?.my_finding?.description, existing?.my_finding?.description),
        remediation: pickFirstNonEmpty(item?.my_finding?.remediation, existing?.my_finding?.remediation),
        line: pickFirstNonEmpty(item?.my_finding?.line, existing?.my_finding?.line),
      },
      raw: item.raw ?? existing.raw ?? item,
    });
  }

  return Array.from(map.values());
}

function wrapFinding(source, finding) {
  return {
    source,
    my_finding: {
      title: pickFirstNonEmpty(finding.title, "Unnamed finding"),
      contract: pickFirstNonEmpty(finding.contract, "Unknown"),
      function: pickFirstNonEmpty(finding.function, ""),
      severity: pickFirstNonEmpty(finding.severity, "Unknown"),
      confidence: pickFirstNonEmpty(finding.confidence, ""),
      description: pickFirstNonEmpty(finding.description, ""),
      remediation: pickFirstNonEmpty(
        finding.remediation,
        finding.fix_recommendation,
        finding.recommendation,
        finding.suggestion,
        finding.fix
      ),
      line: pickFirstNonEmpty(finding.line, finding.lineno, null),
    },
    raw: finding.raw ?? finding,
  };
}

function inferContractNameFromFiles(files) {
  for (const name of files) {
    const n = String(name || "");

    let m =
      n.match(/gptscan[_-]([^.]+)\.json/i) ||
      n.match(/slither[_-]([^.]+)\.json/i);

    if (m && m[1]) {
      return m[1];
    }
  }
  return null;
}

const allItems = $input.all();
const seenFiles = [];
const parseErrors = [];

let chaingptReport = null;
let mythrilReport = null;
let gptscan = null;
let slither = null;
let smartbugs = null;

for (let itemIndex = 0; itemIndex < allItems.length; itemIndex++) {
  const item = allItems[itemIndex];
  const binary = item.binary || {};

  for (const key of Object.keys(binary)) {
    const file = binary[key];
    const fileName = file.fileName || "";
    const normalized = normalizeName(fileName);

    seenFiles.push(fileName);

    let parsed = null;
    try {
      parsed = await parseBinaryJson.call(this, itemIndex, key);
    } catch (error) {
      parseErrors.push(`${fileName}: ${error.message}`);
      continue;
    }

    if (normalized.includes("chaingpt") && normalized.includes("final_audit_report")) {
      chaingptReport = parsed;
      continue;
    }

    if (normalized.includes("mythril") && normalized.includes("final_audit_report")) {
      mythrilReport = parsed;
      continue;
    }

    if (normalized.includes("gptscan")) {
      gptscan = parsed;
      continue;
    }

    if (normalized.includes("slither")) {
      slither = parsed;
      continue;
    }

    if (normalized.includes("smartbugs")) {
      smartbugs = parsed;
      continue;
    }
  }
}

const inferredFromFiles = inferContractNameFromFiles(seenFiles);

const contractName =
  gptscan?.contract ||
  slither?.contract ||
  mythrilReport?.findings?.confirmed?.[0]?.contract ||
  mythrilReport?.findings?.plausible_but_unverified?.[0]?.contract ||
  inferredFromFiles ||
  "Unknown";

const chainConfirmed = asArray(chaingptReport?.findings?.confirmed).map(title =>
  wrapFinding("chaingpt", {
    title,
    contract: contractName,
    severity: "Medium",
    description: title,
  })
);

const chainPlausible = asArray(chaingptReport?.findings?.plausible_but_unverified).map(title =>
  wrapFinding("chaingpt", {
    title,
    contract: contractName,
    severity: "Medium",
    description: title,
  })
);

const chainUnsupported = asArray(chaingptReport?.findings?.unsupported_or_false_positive).map(title =>
  wrapFinding("chaingpt", {
    title,
    contract: contractName,
    severity: "Low",
    description: title,
  })
);

const mythrilConfirmed = asArray(mythrilReport?.findings?.confirmed).map(item =>
  typeof item === "string"
    ? wrapFinding("mythril", {
        title: item,
        contract: contractName,
        severity: "Medium",
        description: item,
      })
    : wrapFinding("mythril", {
        title: item.title,
        contract: item.contract || contractName,
        function: item.function,
        severity: item.severity,
        confidence: item.confidence,
        description: item.description,
        remediation: item.remediation,
        line: item.line || item.lineno,
        raw: item,
      })
);

const mythrilPlausible = asArray(mythrilReport?.findings?.plausible_but_unverified).map(item =>
  typeof item === "string"
    ? wrapFinding("mythril", {
        title: item,
        contract: contractName,
        severity: "Medium",
        description: item,
      })
    : wrapFinding("mythril", {
        title: item.title,
        contract: item.contract || contractName,
        function: item.function,
        severity: item.severity,
        confidence: item.confidence,
        description: item.description,
        remediation: item.remediation,
        line: item.line || item.lineno,
        raw: item,
      })
);

const mythrilUnsupported = asArray(mythrilReport?.findings?.unsupported_or_false_positive).map(item =>
  typeof item === "string"
    ? wrapFinding("mythril", {
        title: item,
        contract: contractName,
        severity: "Low",
        description: item,
      })
    : wrapFinding("mythril", {
        title: item.title,
        contract: item.contract || contractName,
        function: item.function,
        severity: item.severity,
        confidence: item.confidence,
        description: item.description,
        remediation: item.remediation,
        line: item.line || item.lineno,
        raw: item,
      })
);

const gptscanFindings = asArray(gptscan?.results).map(item =>
  wrapFinding("gptscan", {
    title: item.title,
    contract: gptscan?.contract || contractName,
    severity: item.severity,
    description: item.description,
    remediation: item.recommendation,
    line: item?.affectedFiles?.[0]?.range?.start?.line,
    raw: item,
  })
);

const slitherFindings = asArray(slither?.results).map(item =>
  wrapFinding("slither", {
    title: item.check || item.title,
    contract: slither?.contract || contractName,
    severity: item.impact || item.severity,
    confidence: item.confidence,
    description: item.description || item.message,
    line: item?.elements?.[0]?.source_mapping?.lines?.[0],
    raw: item,
  })
);

const confirmed = uniqBy(
  [...chainConfirmed, ...mythrilConfirmed],
  item => makeKey(item.my_finding)
);

const plausible = uniqBy(
  [...chainPlausible, ...mythrilPlausible, ...gptscanFindings, ...slitherFindings],
  item => makeKey(item.my_finding)
).filter(item =>
  !confirmed.some(c => makeKey(c.my_finding) === makeKey(item.my_finding))
);

const unsupported = uniqBy(
  [...chainUnsupported, ...mythrilUnsupported],
  item => makeKey(item.my_finding)
).filter(item =>
  !confirmed.some(c => makeKey(c.my_finding) === makeKey(item.my_finding)) &&
  !plausible.some(p => makeKey(p.my_finding) === makeKey(item.my_finding))
);

const rawTotal = confirmed.length + plausible.length + unsupported.length;
const retained = confirmed.length + plausible.length;
const filteredOut = unsupported.length;

return [{
  json: {
    metrics: {
      raw_total_findings: rawTotal,
      deduped_confirmed_count: confirmed.length,
      deduped_plausible_count: plausible.length,
      deduped_unsupported_count: unsupported.length,
      deduped_total_findings: rawTotal,
      retained_findings: retained,
      redundant_removed: 0,
      filtered_out_count: filteredOut,
      redundancy_reduction_rate: 0,
      total_reduction: filteredOut,
      total_reduction_rate: rawTotal > 0 ? filteredOut / rawTotal : 0,
    },
    adjudication: {
      confirmed,
      plausible_but_unverified: plausible,
      unsupported_or_false_positive: unsupported,
    },
    matched: [],
    missed_by_peer: [],
    debug: {
      seen_files: seenFiles,
      parse_errors: parseErrors,
      contract_name: contractName,
      chaingpt_found: !!chaingptReport,
      mythril_found: !!mythrilReport,
      gptscan_found: !!gptscan,
      slither_found: !!slither,
      smartbugs_found: !!smartbugs,
      chaingpt_confirmed_count: chainConfirmed.length,
      chaingpt_plausible_count: chainPlausible.length,
      gptscan_count: gptscanFindings.length,
      slither_count: slitherFindings.length,
      mythril_confirmed_count: mythrilConfirmed.length,
    },
  }
}];

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

const input = $input.first().json;
const existingMetrics = input.metrics || {};
const adjudication = input.adjudication || {};

const confirmed = asArray(adjudication.confirmed);
const plausible = asArray(adjudication.plausible_but_unverified);
const unsupported = asArray(adjudication.unsupported_or_false_positive);

const currentRawTotal = confirmed.length + plausible.length + unsupported.length;
const hasCurrentCounts = currentRawTotal > 0;

const rawTotalFindings = hasCurrentCounts
  ? currentRawTotal
  : (existingMetrics.raw_total_findings ?? 0);

const dedupedConfirmed = confirmed.length;
const dedupedPlausible = plausible.length;
const dedupedUnsupported = unsupported.length;
const dedupedTotal = currentRawTotal;

const retainedFindings = confirmed.length + plausible.length;
const filteredOutCount = unsupported.length;
const redundantRemoved = existingMetrics.redundant_removed ?? 0;
const redundancyReductionRate = existingMetrics.redundancy_reduction_rate ?? 0;
const totalReduction = filteredOutCount;

const totalReductionRate =
  rawTotalFindings > 0
    ? (filteredOutCount / rawTotalFindings)
    : 0;

return [
  {
    json: {
      ...input,
      metrics: {
        raw_total_findings: rawTotalFindings,
        deduped_confirmed_count: dedupedConfirmed,
        deduped_plausible_count: dedupedPlausible,
        deduped_unsupported_count: dedupedUnsupported,
        deduped_total_findings: dedupedTotal,
        retained_findings: retainedFindings,
        redundant_removed: redundantRemoved,
        filtered_out_count: filteredOutCount,
        redundancy_reduction_rate: redundancyReductionRate,
        total_reduction: totalReduction,
        total_reduction_rate: totalReductionRate,
      },
      debug_metrics: {
        current_confirmed_count: confirmed.length,
        current_plausible_count: plausible.length,
        current_unsupported_count: unsupported.length,
      },
    },
  },
];

const input = $input.first().json;

return [
  {
    json: {
      metrics: input.metrics || {},
      adjudication: input.adjudication || {},
      matched: input.matched || [],
      missed_by_peer: input.missed_by_peer || input.unmatched_my_results || [],
      my_result: input.my_result || [],
      peer_result: input.peer_result || [],
    },
  },
];

const myResults = $input.item.json.my_result || [];
const peerResults = $input.item.json.peer_result || [];
const reports = $input.item.json.reports || [];

function normalizeText(text) {
  return String(text || '')
    .toLowerCase()
    .replace(/[`"'*_#()[\]{}]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function isPeerMatch(a, b) {
  const aTitle = normalizeText(a.title);
  const bTitle = normalizeText(b.title);
  const aDesc = normalizeText(a.description);
  const bDesc = normalizeText(b.description);
  const sameContract = (a.contract || '') === (b.contract || '');

  if (sameContract && aTitle && bTitle && (aTitle.includes(bTitle) || bTitle.includes(aTitle))) {
    return true;
  }

  if (sameContract && aDesc && bDesc && (aDesc.includes(bDesc) || bDesc.includes(aDesc))) {
    return true;
  }

  return false;
}

function reportMentionsFinding(content, finding) {
  const text = normalizeText(content);
  const title = normalizeText(finding.title);
  const desc = normalizeText(finding.description);
  const contract = normalizeText(finding.contract);

  return (
    (title && text.includes(title)) ||
    (desc && desc.length > 20 && text.includes(desc.slice(0, 40))) ||
    (contract && text.includes(contract))
  );
}

const matched = [];
const unmatched_my_results = [];

for (const myF of myResults) {
  const peerHit = peerResults.find(peerF => isPeerMatch(myF, peerF));
  const reportHit = reports.find(r => reportMentionsFinding(r.content, myF));

  if (peerHit || reportHit) {
    matched.push({
      my: myF,
      peer: peerHit || null,
      report: reportHit ? reportHit.title : null,
      match_source: peerHit ? 'peer_result' : 'report_text'
    });
  } else {
    unmatched_my_results.push({
      my: myF,
      reason: 'present_in_raw_input_but_not_reflected_in_peer_or_reports'
    });
  }
}

return [{
  json: {
    my_result: myResults,
    peer_result: peerResults,
    reports,
    matched,
    unmatched_my_results
  }
}];

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function normalizeSeverity(value) {
  return String(value || "")
    .trim()
    .toLowerCase();
}

const input = $input.first().json;

const myResult = asArray(input.my_result);
const peerResult = asArray(input.peer_result);

const matched = [];
const confirmed = [];
const plausible = [];
const unsupported = [];
const unmatchedMyResults = [];

function isLowSeverity(item) {
  const severity =
    item?.severity ||
    item?.my_finding?.severity ||
    item?.impact ||
    "";
  return normalizeSeverity(severity) === "low";
}

// my_result 先放 confirmed，但 low 级别过滤到 unsupported
for (const item of myResult) {
  if (isLowSeverity(item)) {
    unsupported.push({
      source: item.source || "my_result",
      my_finding: item,
      reason: "filtered_out_due_to_low_severity",
    });
  } else {
    confirmed.push({
      source: item.source || "my_result",
      my_finding: item,
      reason: "from_my_result",
    });
  }
}

// peer_result 先放 plausible，但 low 级别过滤到 unsupported
for (const item of peerResult) {
  if (isLowSeverity(item)) {
    unsupported.push({
      source: item.source || "peer_result",
      my_finding: item,
      reason: "filtered_out_due_to_low_severity",
    });
  } else {
    plausible.push({
      source: "raw_detector_only",
      my_finding: item,
      reason: "from_peer_result",
    });
  }
}

return [
  {
    json: {
      metrics: input.metrics || {},
      adjudication: {
        confirmed,
        plausible_but_unverified: plausible,
        unsupported_or_false_positive: unsupported,
      },
      my_result: myResult,
      peer_result: peerResult,
      reports: input.reports || [],
      matched,
      unmatched_my_results: unmatchedMyResults,
      debug: {
        inherited_raw_total_findings: input.metrics?.raw_total_findings ?? null,
        my_result_count: myResult.length,
        peer_result_count: peerResult.length,
        confirmed_count: confirmed.length,
        plausible_count: plausible.length,
        unsupported_count: unsupported.length,
      },
    },
  },
];

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function pickFirstNonEmpty(...values) {
  for (const value of values) {
    if (value == null) continue;
    if (typeof value === "string" && value.trim() === "") continue;
    return value;
  }
  return null;
}

const input = $input.first().json;

const confirmed = asArray(input?.adjudication?.confirmed);
const plausible = asArray(input?.adjudication?.plausible_but_unverified);
const unsupported = asArray(input?.adjudication?.unsupported_or_false_positive);

function normalizeWrappedFinding(entry) {
  const finding = entry?.my_finding || entry || {};

  return {
    source: entry?.source || "unknown",
    title: pickFirstNonEmpty(finding.title, "Unnamed finding"),
    contract: pickFirstNonEmpty(finding.contract, "Unknown"),
    function: pickFirstNonEmpty(finding.function, ""),
    severity: pickFirstNonEmpty(finding.severity, "Unknown"),
    confidence: pickFirstNonEmpty(finding.confidence, ""),
    description: pickFirstNonEmpty(finding.description, ""),
    remediation: pickFirstNonEmpty(
      finding.remediation,
      finding.fix_recommendation,
      finding.recommendation,
      finding.suggestion,
      finding.fix
    ),
    line: pickFirstNonEmpty(finding.line, finding.lineno, null),
    raw: entry?.raw || entry || {},
  };
}

const myResult = confirmed.map(normalizeWrappedFinding);
const peerResult = plausible.map(normalizeWrappedFinding);
const droppedResult = unsupported.map(normalizeWrappedFinding);

const reports = [
  {
    title: "Confirmed Findings",
    status: "completed",
    content: myResult,
    raw: confirmed,
  },
  {
    title: "Plausible But Unverified",
    status: "completed",
    content: peerResult,
    raw: plausible,
  },
  {
    title: "Unsupported Or False Positive",
    status: "completed",
    content: droppedResult,
    raw: unsupported,
  },
];

return [{
  json: {
    my_result: myResult,
    peer_result: peerResult,
    dropped_result: droppedResult,
    reports,
    metrics: input.metrics || {},
    debug: {
      confirmed_count: myResult.length,
      plausible_count: peerResult.length,
      unsupported_count: droppedResult.length,
    },
  }
}];

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function escapeText(value) {
  if (value == null || value === "") return "Unknown";
  return String(value);
}

function normalizeRate(value) {
  if (value == null || value === "") return null;
  return String(value);
}

function renderFindingList(items) {
  if (!items.length) {
    return "None\n";
  }

  return items
    .map((finding, index) => {
      const remediation =
        finding.remediation ||
        finding.fix_recommendation ||
        finding.recommendation ||
        finding.suggestion ||
        finding.fix ||
        "No specific recommendation provided.";

      const lines = [
        `${index + 1}. **${escapeText(finding.title)}**`,
        `   - Contract: ${escapeText(finding.contract)}`,
        `   - Severity: ${escapeText(finding.severity)}`,
      ];

      if (finding.function != null && String(finding.function).trim() !== "") {
        lines.push(`   - Function: ${escapeText(finding.function)}`);
      }

      if (finding.confidence != null && String(finding.confidence).trim() !== "") {
        lines.push(`   - Confidence: ${escapeText(finding.confidence)}`);
      }

      if (finding.line != null && String(finding.line).trim() !== "") {
        lines.push(`   - Line: ${escapeText(finding.line)}`);
      }

      lines.push(`   - Description: ${escapeText(finding.description)}`);
      lines.push(`   - Recommendation: ${escapeText(remediation)}`);

      return `${lines.join("\n")}\n`;
    })
    .join("\n");
}

const input = $input.first().json;
const metrics = input.metrics || {};

const confirmed = asArray(input.confirmed);
const plausible = asArray(input.plausible_but_unverified);
const unsupported = asArray(input.unsupported_or_false_positive);

const rawTotal =
  metrics.raw_total_findings ??
  confirmed.length + plausible.length + unsupported.length;

const retained =
  metrics.retained_findings ??
  confirmed.length + plausible.length;

const filteredOut =
  metrics.filtered_out_count ??
  unsupported.length;

const reductionRate =
  normalizeRate(metrics.total_reduction_rate) ||
  "0.00%";

const falsePositiveRate =
  normalizeRate(input.false_positive_rate) ||
  "0.00%";

let report = "";

report += "# Smart Contract Audit Report\n\n";
report += `**Status**: ${escapeText(input.status || "Completed")}\n\n`;

report += "## Total Findings\n";
report += `- Raw Total Findings: ${rawTotal}\n`;
report += `- Retained Findings: ${retained}\n`;
report += `- Filtered Out: ${filteredOut}\n`;
report += `- Total Reduction Rate: ${reductionRate}\n`;
report += `- False Positive Rate: ${falsePositiveRate}\n\n`;

report += "## Confirmed Findings\n\n";
report += renderFindingList(confirmed);
report += "\n";

report += "## Plausible But Unverified Findings\n\n";
report += renderFindingList(plausible);
report += "\n";

report += "## Unsupported Or False Positive\n\n";
report += renderFindingList(unsupported);

const fileName = "Final_Audit_Report.md";
const base64Data = Buffer.from(report, "utf8").toString("base64");

return [
  {
    json: {
      markdown: report,
      report,
      fileName,
    },
    binary: {
      data: {
        data: base64Data,
        mimeType: "text/markdown",
        fileName,
      },
    },
  },
];

const input = $input.item.json || {};
const metrics = input.metrics || {};
const adjudication = input.adjudication || {};

function compactFinding(item) {
  const f = item.my_finding || {};
  return {
    title: f.title || '',
    contract: f.contract || '',
    function: f.function || '',
    severity: f.severity || '',
    confidence: f.confidence || '',
    description: (f.description || '').slice(0, 300)
  };
}

return [{
  json: {
    metrics: {
      raw_total_findings: metrics.raw_total_findings || 0,
      retained_findings: metrics.retained_findings || 0,
      filtered_out_count: metrics.filtered_out_count || 0,
      total_reduction_rate: metrics.total_reduction_rate || 0
    },
    confirmed: (adjudication.confirmed || []).slice(0, 10).map(compactFinding),
    plausible_but_unverified: (adjudication.plausible_but_unverified || []).slice(0, 10).map(compactFinding),
    unsupported_or_false_positive: (adjudication.unsupported_or_false_positive || []).slice(0, 10).map(compactFinding)
  }
}];

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function pickFirstNonEmpty(...values) {
  for (const value of values) {
    if (value == null) continue;
    if (typeof value === "string" && value.trim() === "") continue;
    return value;
  }
  return null;
}

function normalizeText(value) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function makeKey(item) {
  const f = item?.my_finding || item || {};
  return [
    normalizeText(f.title),
    normalizeText(f.contract),
    normalizeText(f.severity),
  ].join("||");
}

function toPercent(value) {
  if (value == null || value === "") return "0.00%";
  const num = Number(value);
  if (Number.isNaN(num)) return String(value);
  return `${(num * 100).toFixed(2)}%`;
}

function wrapAiFinding(item) {
  return {
    source: "ai_summary",
    my_finding: {
      title: pickFirstNonEmpty(item.title, "Unnamed finding"),
      contract: pickFirstNonEmpty(item.contract, "Unknown"),
      function: pickFirstNonEmpty(item.function, ""),
      severity: pickFirstNonEmpty(item.severity, "Unknown"),
      confidence: pickFirstNonEmpty(item.confidence, ""),
      description: pickFirstNonEmpty(item.description, ""),
      remediation: pickFirstNonEmpty(
        item.remediation,
        item.fix_recommendation,
        item.recommendation,
        item.suggestion,
        item.fix
      ),
      line: pickFirstNonEmpty(item.line, item.lineno, null),
    },
    raw: item,
  };
}

function enrichList(baseList, aiList) {
  const aiMap = new Map(aiList.map(item => [makeKey(item), item]));

  return baseList.map(item => {
    const key = makeKey(item);
    const ai = aiMap.get(key);
    if (!ai) return item;

    return {
      ...item,
      my_finding: {
        ...item.my_finding,
        function: pickFirstNonEmpty(ai?.my_finding?.function, item?.my_finding?.function),
        confidence: pickFirstNonEmpty(ai?.my_finding?.confidence, item?.my_finding?.confidence),
        description: pickFirstNonEmpty(ai?.my_finding?.description, item?.my_finding?.description),
        remediation: pickFirstNonEmpty(ai?.my_finding?.remediation, item?.my_finding?.remediation),
        line: pickFirstNonEmpty(ai?.my_finding?.line, item?.my_finding?.line),
      },
      raw: {
        detector: item.raw || item,
        ai: ai.raw || ai,
      },
    };
  });
}

function unwrapFinding(entry) {
  const finding = entry?.my_finding || {};
  return {
    source: entry?.source || "unknown",
    title: pickFirstNonEmpty(finding.title, "Unnamed finding"),
    contract: pickFirstNonEmpty(finding.contract, "Unknown"),
    function: pickFirstNonEmpty(finding.function, ""),
    severity: pickFirstNonEmpty(finding.severity, "Unknown"),
    confidence: pickFirstNonEmpty(finding.confidence, ""),
    description: pickFirstNonEmpty(finding.description, ""),
    remediation: pickFirstNonEmpty(
      finding.remediation,
      finding.fix_recommendation,
      finding.recommendation,
      finding.suggestion,
      finding.fix
    ),
    line: pickFirstNonEmpty(finding.line, finding.lineno, null),
    raw: entry?.raw || entry || {},
  };
}

const inputs = $input.all().map(i => i.json);

// 上半支路：Evaluation JSON Export
const evalSource =
  inputs.find(i => i.metrics && i.adjudication) || {};

// 下半支路：AI Summary JSON Parser
const aiSource =
  inputs.find(i =>
    Array.isArray(i.confirmed) ||
    Array.isArray(i.plausible_but_unverified) ||
    Array.isArray(i.unsupported_or_false_positive)
  ) || {};

const baseConfirmed = asArray(evalSource?.adjudication?.confirmed);
const basePlausible = asArray(evalSource?.adjudication?.plausible_but_unverified);
const baseUnsupported = asArray(evalSource?.adjudication?.unsupported_or_false_positive);

const aiConfirmed = asArray(aiSource.confirmed).map(wrapAiFinding);
const aiPlausible = asArray(aiSource.plausible_but_unverified).map(wrapAiFinding);
const aiUnsupported = asArray(aiSource.unsupported_or_false_positive).map(wrapAiFinding);

const mergedConfirmed = enrichList(baseConfirmed, aiConfirmed);
const mergedPlausible = enrichList(basePlausible, aiPlausible);
const mergedUnsupported = enrichList(baseUnsupported, aiUnsupported);

const confirmed = mergedConfirmed.map(unwrapFinding);
const plausible = mergedPlausible.map(unwrapFinding);
const unsupported = mergedUnsupported.map(unwrapFinding);

const metrics = evalSource.metrics || {};

const rawTotal =
  metrics.raw_total_findings ??
  metrics.deduped_total_findings ??
  confirmed.length + plausible.length + unsupported.length;

const retained =
  metrics.retained_findings ??
  confirmed.length + plausible.length;

const filteredOut =
  metrics.filtered_out_count ??
  unsupported.length;

const totalReductionRate =
  metrics.total_reduction_rate != null
    ? toPercent(metrics.total_reduction_rate)
    : rawTotal > 0
      ? toPercent(filteredOut / rawTotal)
      : "0.00%";

const falsePositiveRate =
  rawTotal > 0
    ? toPercent(unsupported.length / rawTotal)
    : "0.00%";

return [
  {
    json: {
      status: "Completed",
      metrics: {
        raw_total_findings: rawTotal,
        retained_findings: retained,
        filtered_out_count: filteredOut,
        total_reduction_rate: totalReductionRate,
      },
      confirmed,
      plausible_but_unverified: plausible,
      unsupported_or_false_positive: unsupported,
      false_positive_rate: falsePositiveRate,
      debug: {
        eval_confirmed_count: baseConfirmed.length,
        eval_plausible_count: basePlausible.length,
        ai_confirmed_count: aiConfirmed.length,
        ai_plausible_count: aiPlausible.length,
        first_plausible_remediation: plausible[0]?.remediation || null,
      },
    },
  },
];

const input = $input.first().json;

function extractText(payload) {
  if (typeof payload?.output_text === "string") {
    return payload.output_text;
  }

  if (Array.isArray(payload?.output)) {
    for (const item of payload.output) {
      if (Array.isArray(item?.content)) {
        for (const part of item.content) {
          if (typeof part?.text === "string" && part.text.trim()) {
            return part.text;
          }
        }
      }
    }
  }

  if (typeof payload?.text === "string") {
    return payload.text;
  }

  return null;
}

const rawText = extractText(input);

if (!rawText) {
  throw new Error("AI Summary JSON text not found in node output.");
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error(`Failed to parse AI Summary JSON: ${error.message}\nRaw text:\n${rawText}`);
}

return [
  {
    json: parsed,
  },
];
